// Resolve cidade/uf -> NOME OFICIAL IBGE (com acentos), tolerante a
// ausência de acentos E a erros de digitação. Os endpoints de leads são
// acento-sensíveis e não perdoam typos; aqui devolvemos sempre o nome
// canônico do IBGE quando houver um match razoável.

const dadosIa = $input.item.json;

let cidade = dadosIa.cidade || '';
let uf = dadosIa.uf || '';
let limite = dadosIa.limite || 20;

// Se a IA mandou tudo num campo "query" (ex: "Diadema, SP" ou "Diadema - SP")
if (dadosIa.query && !cidade) {
    let partes = dadosIa.query.split(/,| - |-/); // Separa usando vírgula ou traço
    cidade = partes[0] ? partes[0].trim() : '';
    uf = partes[1] ? partes[1].trim() : '';
}

// Fallbacks de segurança
cidade = (cidade || 'Birigui').trim();
uf = (uf || 'SP').trim().toUpperCase();

// Remove acentos + caixa baixa para comparação tolerante.
function fold(s) {
    return String(s || '')
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .toLowerCase()
        .replace(/\s+/g, ' ')
        .trim();
}

// Distância de Levenshtein (tolera erros de digitação).
function levenshtein(a, b) {
    a = a || '';
    b = b || '';
    const m = a.length;
    const n = b.length;
    if (!m) return n;
    if (!n) return m;
    let prev = new Array(n + 1);
    for (let j = 0; j <= n; j++) prev[j] = j;
    for (let i = 1; i <= m; i++) {
        const cur = [i];
        for (let j = 1; j <= n; j++) {
            const cost = a[i - 1] === b[j - 1] ? 0 : 1;
            cur[j] = Math.min(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + cost);
        }
        prev = cur;
    }
    return prev[n];
}

// Tenta resolver o nome oficial (acentuado) da cidade via IBGE.
// Defensivo: qualquer falha mantém a cidade original (comportamento atual).
try {
    if (uf && /^[A-Z]{2}$/.test(uf)) {
        const municipios = await this.helpers.httpRequest({
            method: 'GET',
            url: `https://servicodados.ibge.gov.br/api/v1/localidades/estados/${uf}/municipios`,
            json: true,
            timeout: 8000,
        });
        if (Array.isArray(municipios) && municipios.length) {
            const alvo = fold(cidade);
            // 1) match exato (sem acento)
            let achado = municipios.find((m) => fold(m.nome) === alvo);
            // 2) começa-com único (cobre abreviações como "Balneario")
            if (!achado) {
                const candidatos = municipios.filter((m) => fold(m.nome).startsWith(alvo));
                if (candidatos.length === 1) achado = candidatos[0];
            }
            // 3) contém único (digitou só parte do nome composto)
            if (!achado && alvo.length >= 4) {
                const candidatos = municipios.filter((m) => fold(m.nome).includes(alvo));
                if (candidatos.length === 1) achado = candidatos[0];
            }
            // 4) fuzzy: menor distância de Levenshtein dentro de um limiar
            //    proporcional ao tamanho do nome (cobre "escrevi errado").
            if (!achado) {
                let melhor = null;
                let melhorDist = Infinity;
                let segundaDist = Infinity;
                for (const m of municipios) {
                    const d = levenshtein(alvo, fold(m.nome));
                    if (d < melhorDist) {
                        segundaDist = melhorDist;
                        melhorDist = d;
                        melhor = m;
                    } else if (d < segundaDist) {
                        segundaDist = d;
                    }
                }
                // tolera ~34% do tamanho digitado (mín. 2 erros) e exige que o
                // melhor candidato seja claramente melhor que o segundo.
                const limiar = Math.max(2, Math.floor(alvo.length * 0.34));
                if (melhor && melhorDist <= limiar && melhorDist < segundaDist) {
                    achado = melhor;
                }
            }
            if (achado && achado.nome) {
                cidade = achado.nome; // nome oficial COM acento
            }
        }
    }
} catch (e) {
    // IBGE indisponível -> segue com a cidade informada
}

return {
    json: {
        cidade: cidade,
        uf: uf,
        limite: limite
    }
};

// Função para corrigir caracteres corrompidos (UTF-8 vs ISO-8859-1)
function fixEncoding(text) {
    if (typeof text !== 'string') return text;
    try {
        return decodeURIComponent(escape(text));
    } catch (e) {
        return text
            .replace(/茫/g, 'ã')
            .replace(/茅/g, 'é')
            .replace(/铆/g, 'í')
            .replace(/贳/g, 'ó')
            .replace(/煤/g, 'ú')
            .replace(/锚/g, 'ê')
            .replace(/芒/g, 'â');
    }
}

const leadsBrutos = $input.item.json.retorno || [];

// FASE 3: DESCARTE DE BAIXADAS/INATIVAS E CPF
const leadsValidos = leadsBrutos.filter(lead => {
    // Descartar tipoCNPJ = CPF (pessoa física sem loja formal)
    if (lead.tipoCNPJ === 'CPF') return false;
    
    // Descartar situacaoCadastral BAIXADA/INAPTA/SUSPENSA/NULA
    const situacao = (lead.situacaoCadastral || '').toUpperCase();
    if (situacao.includes('BAIXAD') || situacao.includes('INAPT') || 
        situacao.includes('SUSPENS') || situacao.includes('NULA')) {
        return false;
    }
    
    return true;
});

const leadsFiltrados = leadsValidos.map(lead => ({
    // Identificação Básica
    empresa: fixEncoding(lead.razaoSocial),
    nomeFantasia: fixEncoding(lead.nomeFantasia),
    cnpj: lead.cnpjCompleto || null,

    // Localização para o Roteiro
    endereco: fixEncoding(lead.enderecoCompleto),
    bairro: fixEncoding(lead.bairro),
    cidade: fixEncoding(lead.cidade),
    uf: lead.uf,
    cep: lead.cep,  // FASE 3b
    tipoLogradouro: lead.tipoLogradouro,

    // Contatos diretos
    telefones: lead.telefones || [],
    emails: lead.emails || [],
    sites: lead.sites || [],

    // Mídia
    fotos: lead.fotos || [],

    // Presença Digital e Redes Sociais
    redesSociais: lead.redesSociais || [],
    possuiPresencaDigital: lead.possuiPresencaDigital,

    // Inteligência de Vendas
    atividadeEconomica: fixEncoding(lead.atividadeEconomica),
    atividadeEconomicaSk: lead.atividadeEconomicaSk,  // FASE 3b
    porte: lead.porte,
    dataAbertura: lead.dataAbertura,
    faturamento: lead.indicadorAtividade?.faixaFaturamento,
    numeroFuncionarios: lead.indicadorAtividade?.numeroFuncionarios,
    natureza: fixEncoding(lead.naturezaJuridica),
    
    // FASE 3b: Novos campos cadastrais e tributários
    situacaoCadastral: lead.situacaoCadastral,
    tipoCNPJ: lead.tipoCNPJ,
    regimeTributario: lead.regimeTributario,
    simples: lead.simples,
    mei: lead.mei,
    
    empresaCliente: lead.empresaCliente,
    empresaProspect: lead.empresaProspect,
    
    score: {
        nota: lead.notaICP,
        classificacao: lead.classificacaoICP,
        descricao: fixEncoding(lead.descricaoClassificacaoICP)
    },
    
    // FASE 3b: IDs de controle
    idConsulta: lead.idConsulta,
    municipioSk: lead.municipioSk,

    // Origem do dado
    fonte: 'oporttuna'
}));

// FASE 3: CÁLCULO DE PERFIL INFANTIL E DIGITAL
function calcularPerfilInfantil(l) {
    const cnae = (l.atividadeEconomica || '').toLowerCase();
    const infantilKeywords = ['infantil', 'bebê', 'bebe', 'criança', 'crianca', 'kids', 'baby'];
    return infantilKeywords.some(kw => cnae.includes(kw));
}

function temPresencaDigital(l) {
    return l.possuiPresencaDigital === 'SIM' || 
           (l.redesSociais || []).length > 0 || 
           (l.sites || []).length > 0;
}

function digitalScore(l) {
    let s = 0;
    if ((l.redesSociais || []).length) s += 4;
    if (l.possuiPresencaDigital === 'SIM') s += 3;
    if ((l.fotos || []).length) s += 2;
    if ((l.sites || []).length) s += 2;
    if ((l.telefones || []).length) s += 1;
    if ((l.emails || []).length) s += 1;
    return s;
}

// Adicionar campos calculados
leadsFiltrados.forEach(lead => {
    lead.perfilInfantil = calcularPerfilInfantil(lead);
    lead.temPresencaDigital = temPresencaDigital(lead);
});

// PRIORIZAÇÃO: perfil infantil + presença digital primeiro
leadsFiltrados.sort((a, b) => {
    if (a.perfilInfantil !== b.perfilInfantil) return b.perfilInfantil ? 1 : -1;
    return digitalScore(b) - digitalScore(a);
});

return {
    json: {
        ok: true,
        fonte: 'oporttuna',
        origem: 'api_oporttuna_leads_por_cidade',
        total: leadsFiltrados.length,
        totalBruto: leadsBrutos.length,
        totalDescartado: leadsBrutos.length - leadsValidos.length,
        leads: leadsFiltrados
    }
};
